function calcTsPopup(){var dateEl=document.getElementById('tsp-date');var hourEl=document.getElementById('tsp-hour');var minEl=document.getElementById('tsp-min');var tzEl=document.getElementById('tsp-tz');var resEl=document.getElementById('tsp-result');var humEl=document.getElementById('tsp-result-human');if(!dateEl||!resEl)return;var date=dateEl.value;var hour=Math.max(0,Math.min(23,parseInt(hourEl.value)||0));var min=Math.max(0,Math.min(59,parseInt(minEl.value)||0));var tz=tzEl?tzEl.value:'America/Mazatlan';if(!date){resEl.textContent='—';humEl.textContent='';return;}
try{var localStr=date+'T'+String(hour).padStart(2,'0')+':'+String(min).padStart(2,'0')+':00';var refUtc=new Date(localStr+'Z');var fmt2=new Intl.DateTimeFormat('en',{timeZone:tz,year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false});var parts=fmt2.formatToParts(refUtc);var p={};parts.forEach(function(x){p[x.type]=x.value;});var tzShownAsUtc=new Date(p.year+'-'+p.month+'-'+p.day+'T'+p.hour+':'+p.minute+':'+p.second+'Z');var offsetMs=refUtc.getTime()-tzShownAsUtc.getTime();var trueUtc=new Date(refUtc.getTime()+offsetMs);var ts=Math.floor(trueUtc.getTime()/1000);resEl.textContent=ts;var readable=new Intl.DateTimeFormat('es-MX',{timeZone:tz,weekday:'short',year:'numeric',month:'short',day:'numeric',hour:'2-digit',minute:'2-digit',hour12:false}).format(trueUtc);humEl.textContent='equivale a: '+readable+' ('+tz+')';}catch(e){resEl.textContent='Error';humEl.textContent='';}}
function copyTsResult(){var resEl=document.getElementById('tsp-result');if(!resEl||resEl.textContent==='—'||resEl.textContent==='Error')return;navigator.clipboard.writeText(resEl.textContent).then(function(){var btn=document.getElementById('tsp-copy-btn');if(btn){btn.textContent=t('copied_ok');setTimeout(function(){btn.textContent=t('copy');},2000);}}).catch(function(){var el=document.createElement('textarea');el.value=resEl.textContent;document.body.appendChild(el);el.select();document.execCommand('copy');document.body.removeChild(el);var btn=document.getElementById('tsp-copy-btn');if(btn){btn.textContent=t('copied_ok');setTimeout(function(){btn.textContent=t('copy');},2000);}});}
