function calculateAutoPosition(text){let pos;if(text.alignment==='manual'){pos={x:text.x,y:text.y,align:'center'};}else{const{width:w,height:h}=imageData,{padding_x:px,padding_y:py}=text;const estimatedTextHeight=text.font_size*1.2;const positions={'top-left':{x:px,y:py,align:'left'},'top-center':{x:w/2,y:py,align:'center'},'top-right':{x:w-px,y:py,align:'right'},'middle-left':{x:px,y:h/2,align:'left'},'center':{x:w/2,y:h/2,align:'center'},'middle-right':{x:w-px,y:h/2,align:'right'},'bottom-left':{x:px,y:h-py-estimatedTextHeight,align:'left'},'bottom-center':{x:w/2,y:h-py-estimatedTextHeight,align:'center'},'bottom-right':{x:w-px,y:h-py-estimatedTextHeight,align:'right'}};pos=positions[text.auto_alignment]||{x:text.x,y:text.y,align:'center'};}
if(text.canvas_padding_enabled){const pv=text.canvas_padding_value||0;if(text.canvas_padding_side==='right'){pos={...pos,x:(imageData.width||0)-pv,align:'right'};}else{pos={...pos,x:pv,align:'left'};}}
return pos;}
function insertField(index,field){const textarea=document.getElementById(`textarea-${index}`);if(!textarea.value||textarea.value.trim()===''){textarea.value=field;updateTextProp(index,'text',field);textarea.focus();textarea.setSelectionRange(field.length,field.length);checkCustomFields(index);return;}
const start=textarea.selectionStart;const end=textarea.selectionEnd;const text=textarea.value;const newText=text.substring(0,start)+field+text.substring(end);textarea.value=newText;updateTextProp(index,'text',newText);const newCursorPos=start+field.length;textarea.focus();textarea.setSelectionRange(newCursorPos,newCursorPos);checkCustomFields(index);}
